private boolean isShortOption(String token)
{
    // short options (-S, -SV, -S=V, -SV1=V2, -S1S2)
    if (token == null || !token.startsWith("-") || token.length() == 1)
    {
        return false;
    }

    // Iterate through the token to handle concatenated short options and options with values
    for (int i = 1; i < token.length(); i++) {
        char c = token.charAt(i);
        if (c == '=') {
            // If we encounter '=', the rest is a value, so we stop checking further
            break;
        }
        if (options.hasShortOption(String.valueOf(c))) {
            return true;
        }
    }
    return false;
}

