private Node tryFoldArrayAccess(Node n, Node left, Node right) {
  Node parent = n.getParent();
  // If GETPROP/GETELEM is used as assignment target the array literal is
  // acting as a temporary we can't fold it here:
  //    "[][0] += 1"

  if (parent != null && (parent.getType() == Token.ASSIGN || parent.getType() == Token.INC || parent.getType() == Token.DEC)) {
    return n;
  }

  if (right.getType() != Token.NUMBER) {
    // Sometimes people like to use complex expressions to index into
    // arrays, or strings to index into array methods.
    return n;
  }

  double index = right.getDouble();
  int intIndex = (int) index;
  if (intIndex != index) {
    error(INVALID_GETELEM_INDEX_ERROR, right);
    return n;
  }

  if (intIndex < 0) {
    error(INDEX_OUT_OF_BOUNDS_ERROR, right);
    return n;
  }

  Node elem = left.getFirstChild();
  for (int i = 0; elem != null && i < intIndex; i++) {
    elem = elem.getNext();
  }

  if (elem == null) {
    error(INDEX_OUT_OF_BOUNDS_ERROR, right);
    return n;
  }

  if (elem.getType() == Token.EMPTY) {
    elem = NodeUtil.newUndefinedNode(elem);
  } else {
    left.removeChild(elem);
  }

  // Replace the entire GETELEM with the value
  n.getParent().replaceChild(n, elem);
  reportCodeChange();
  return elem;
}

public boolean isSubtype(JSType other) {
  if (!(other instanceof ArrowType)) {
    return false;
  }

  ArrowType that = (ArrowType) other;

  // this.returnType <: that.returnType (covariant)
  if (!this.returnType.isSubtype(that.returnType)) {
    return false;
  }

  // that.paramType[i] <: this.paramType[i] (contravariant)
  Node thisParam = parameters.getFirstChild();
  Node thatParam = that.parameters.getFirstChild();
  while (thisParam != null && thatParam != null) {
    JSType thisParamType = thisParam.getJSType();
    JSType thatParamType = thatParam.getJSType();
    if (thisParamType != null) {
      if (thatParamType == null || !thatParamType.isSubtype(thisParamType)) {
        return false;
      }
    }

    boolean thisIsVarArgs = thisParam.isVarArgs();
    boolean thatIsVarArgs = thatParam.isVarArgs();

    // If 'this' is varargs, 'that' must also be varargs or have fewer required params
    if (thisIsVarArgs && !thatIsVarArgs && thatParam.getNext() != null) {
      return false;
    }

    // If 'that' is varargs, 'this' must also be varargs or have fewer required params
    if (thatIsVarArgs && !thisIsVarArgs && thisParam.getNext() != null) {
      return false;
    }

    // don't advance if we have variable arguments
    if (!thisIsVarArgs) {
      thisParam = thisParam.getNext();
    }
    if (!thatIsVarArgs) {
      thatParam = thatParam.getNext();
    }

    // both var_args indicates the end
    if (thisIsVarArgs && thatIsVarArgs) {
      thisParam = null;
      thatParam = null;
    }
  }

  // If 'this' has more required parameters than 'that', 'that' is not a subtype
  if (thisParam != null && !thisParam.isVarArgs()) {
    return false;
  }

  return true;
}

public void matchConstraint(JSType constraint) {
  // We only want to match constraints on anonymous types.
  if (hasReferenceName()) {
    return;
  }

  // Handle the case where the constraint object is a record type.
  if (constraint.isRecordType()) {
    matchRecordTypeConstraint(constraint.toObjectType());
  }

  // Handle the case where the constraint is a union type containing record types.
  if (constraint.isUnionType()) {
    processUnionType(constraint.toMaybeUnionType());
  }
}

private void processUnionType(UnionType unionType) {
  if (unionType == null || unionType.getAlternates() == null) {
    return;
  }

  for (JSType alt : unionType.getAlternates()) {
    if (alt.isRecordType()) {
      matchRecordTypeConstraint(alt.toObjectType());
    } else if (alt.isUnionType()) {
      // Recursively process nested union types
      processUnionType(alt.toMaybeUnionType());
    }
  }
}

