      sb.append(property);
      sb.append(": ");
      if (forAnnotations && getPropertyType(property) instanceof ProxyObjectType) {
        sb.append("?");
      } else {
        sb.append(getPropertyType(property).toString());
      }

      ++i;
      if (!forAnnotations && i == MAX_PRETTY_PRINTED_PROPERTIES) {
        sb.append(", ...");
        break;
      }
    }

    sb.append("}");

    prettyPrint = true;
    return sb.toString();
  } else {
    return "{...}";
  }
}

