    if (callNode.hasOneChild()
        && OBJECT_METHODS_WITHOUT_SIDEEFFECTS.contains(
              nameNode.getLastChild().getString())) {
      return false;
    }

    if (callNode.isOnlyModifiesThisCall()
        && evaluatesToLocalValue(nameNode.getFirstChild())) {
      return false;
    }

    // Functions in the "Math" namespace have no side effects.
    Set<String> MATH_METHODS_WITHOUT_SIDEEFFECTS = ImmutableSet.of("sin", "cos", "tan", "random", "abs", "ceil", "floor", "sqrt", "log", "exp", "pow");
    if (nameNode.getFirstChild().getType() == Token.NAME && "Math".equals(nameNode.getFirstChild().getString()) && MATH_METHODS_WITHOUT_SIDEEFFECTS.contains(nameNode.getLastChild().getString())) {
      return false;
    }

    if (compiler != null && !compiler.hasRegExpGlobalReferences()) {
      if (nameNode.getFirstChild().getType() == Token.REGEXP
          && REGEXP_METHODS.contains(nameNode.getLastChild().getString())) {
        return false;
      } else if (nameNode.getFirstChild().getType() == Token.STRING
          && STRING_REGEXP_METHODS.contains(
