public static long parseOctal(final byte[] buffer, final int offset, final int length) {
    long    result = 0;
    int     end = offset + length;
    int     start = offset;

    if (length < 2){
        throw new IllegalArgumentException("Length "+length+" must be at least 2");
    }

    if (buffer[start] == 0) {
        return 0L;
    }

    // Skip leading spaces
    while (start < end && buffer[start] == ' '){
        start++;
    }

    if (start >= end) {
        throw new IllegalArgumentException(
                exceptionMessage(buffer, offset, length, start, buffer[start]));
    }

    // Must have trailing NUL or space
    byte trailer;
    trailer = buffer[end-1];
    if (trailer == 0 || trailer == ' '){
        end--;
    } else {
        throw new IllegalArgumentException(
                exceptionMessage(buffer, offset, length, end-1, trailer));
    }
    // May have additional NULs or spaces
    while (end > start && (buffer[end - 1] == 0 || buffer[end - 1] == ' ')){
        end--;
    }

    for ( ;start < end; start++) {
        final byte currentByte = buffer[start];
        // CheckStyle:MagicNumber OFF
        if (currentByte < '0' || currentByte > '7'){
            throw new IllegalArgumentException(
                    exceptionMessage(buffer, offset, length, start, currentByte));
        }
        if (result > (Long.MAX_VALUE - (currentByte - '0')) / 8) {
            throw new IllegalArgumentException("Octal number exceeds Long.MAX_VALUE");
        }
        result = (result << 3) + (currentByte - '0'); // convert from ASCII
        // CheckStyle:MagicNumber ON
    }

    return result;
}

private void writeBits(final DataOutput header, final BitSet bits, final int length) throws IOException {
    if (header == null || bits == null) {
        throw new IllegalArgumentException("Header and bits cannot be null");
    }
    int cache = 0;
    int shift = 7;
    for (int i = 0; i < length; i++) {
        cache |= ((bits.get(i) ? 1 : 0) << shift);
        --shift;
        if (shift == -1) {
            header.writeByte((byte) cache);
            shift = 7;
            cache = 0;
        }
    }
    if (length > 0 && shift < 7) {
        header.writeByte((byte) cache);
    }
}

InputStream decode(final InputStream in, final Coder coder,
        byte[] password) throws IOException {
    if (coder == null || coder.properties == null || coder.properties.length < 5) {
        throw new IllegalArgumentException("Coder or its properties are invalid");
    }
    byte propsByte = coder.properties[0];
    long dictSize = 0;
    for (int i = 0; i < 4; i++) {
        dictSize |= ((long) (coder.properties[i] & 0xFF)) << (8 * i);
    }
    if (dictSize < 0 || dictSize > LZMAInputStream.DICT_SIZE_MAX) {
        throw new IOException("Dictionary size out of valid range");
    }
    return new LZMAInputStream(in, -1, propsByte, (int) dictSize);
}

