public static boolean verifyCheckSum(byte[] header) {
    if (header == null || header.length < CHKSUM_OFFSET + CHKSUMLEN) {
        return false;
    }

    long storedSum = 0;
    long unsignedSum = 0;
    long signedSum = 0;

    for (int i = CHKSUM_OFFSET; i < CHKSUM_OFFSET + CHKSUMLEN; i++) {
        byte b = header[i];
        if ('0' <= b && b <= '7') {
            storedSum = storedSum * 8 + (b - '0');
        }
        b = ' ';
        unsignedSum += 0xff & b;
        signedSum += b;
    }

    for (int i = 0; i < CHKSUM_OFFSET; i++) {
        byte b = header[i];
        unsignedSum += 0xff & b;
        signedSum += b;
    }

    for (int i = CHKSUM_OFFSET + CHKSUMLEN; i < header.length; i++) {
        byte b = header[i];
        unsignedSum += 0xff & b;
        signedSum += b;
    }

    return storedSum == unsignedSum || storedSum == signedSum;
}

Map<String, String> parsePaxHeaders(final InputStream i)
    throws IOException {
    final Map<String, String> headers = new HashMap<String, String>(globalPaxHeaders);
    // Format is "length keyword=value\n";
    while(true){ // get length
        int ch;
        int len = 0;
        int read = 0;
        while((ch = i.read()) != -1) {
            read++;
            if (ch == ' '){
                // Get keyword
                final ByteArrayOutputStream coll = new ByteArrayOutputStream();
                while((ch = i.read()) != -1) {
                    read++;
                    if (ch == '='){ // end of keyword
                        final String keyword = coll.toString(CharsetNames.UTF_8);
                        // Get rest of entry
                        final int restLen = len - read;
                        if (restLen <= 0) { // only NL or invalid
                            headers.remove(keyword);
                        } else {
                            final byte[] rest = new byte[restLen];
                            final int got = IOUtils.readFully(i, rest);
                            if (got != restLen) {
                                throw new IOException("Failed to read "
                                                      + "Paxheader. Expected "
                                                      + restLen
                                                      + " bytes, read "
                                                      + got);
                            }
                            // Drop trailing NL
                            final String value = new String(rest, 0,
                                                      restLen - 1, CharsetNames.UTF_8);
                            headers.put(keyword, value);
                        }
                        break;
                    }
                    coll.write((byte) ch);
                }
                break; // Processed single header
            }
            if (ch < '0' || ch > '9') {
                throw new IOException("Invalid character in length field: " + (char) ch);
            }
            len *= 10;
            len += ch - '0';
        }
        if (ch == -1 || len <= 0){ // EOF or invalid length
            break;
        }
    }
    return headers;
}

public boolean isDirectory() {
    if (file != null) {
        return file.isDirectory();
    }

    if (linkFlag == LF_DIR) {
        return true;
    }

    return false;
}

public ZipArchiveEntry getNextZipEntry() throws IOException {
    boolean firstEntry = true;
    if (closed || hitCentralDirectory) {
        return null;
    }
    if (current != null) {
        closeEntry();
        firstEntry = false;
    }

    try {
        if (firstEntry) {
            readFirstLocalFileHeader(LFH_BUF);
        } else {
            readFully(LFH_BUF);
        }
    } catch (final EOFException e) {
        return null;
    }

    final ZipLong sig = new ZipLong(LFH_BUF);
    if (sig.equals(ZipLong.CFH_SIG) || sig.equals(ZipLong.AED_SIG)) {
        hitCentralDirectory = true;
        skipRemainderOfArchive();
        return null;
    }
    if (!sig.equals(ZipLong.LFH_SIG)) {
        throw new ZipException("Unexpected record signature: " + sig);
    }

    int off = WORD;
    current = new CurrentEntry();

    final int versionMadeBy = ZipShort.getValue(LFH_BUF, off);
    off += SHORT;
    current.entry.setPlatform((versionMadeBy >> ZipFile.BYTE_SHIFT) & ZipFile.NIBLET_MASK);

