    if (token == JsonToken.NAME) {
        nextName();
        if (stackSize > 1 && stack[stackSize - 2] instanceof JsonObject) {
            pathNames[stackSize - 2] = "null";
        }
    } else {
        popStack();
        if (stackSize > 0 && stack[stackSize - 1] instanceof JsonArray) {
            pathIndices[stackSize - 1]++;
        }
    }
}

