public <T> MappingIterator<T> readValues(byte[] src, int offset, int length)
    throws IOException, JsonProcessingException
{
    if (src == null || src.length == 0 || offset < 0 || length <= 0 || offset + length > src.length) {
        throw new IllegalArgumentException("Invalid input parameters");
    }
    if (_dataFormatReaders != null) {
        return _detectBindAndReadValues(_dataFormatReaders.findFormat(src, offset, length), false);
    }
    JsonParser parser = _parserFactory.createParser(src, offset, length);
    // Conditionally move to the first token if needed
    if (parser.getCurrentToken() == null) {
        parser.nextToken();
    }
    return _bindAndReadValues(_considerFilter(parser, true));
}

