    final String UTF16_LE_BOM = "\uFFFE";
    if (str.startsWith(UTF8_BOM)) {
        return str.substring(1);
    } else if (str.startsWith(UTF16_BE_BOM) || str.startsWith(UTF16_LE_BOM)) {
        return str.substring(1);
    }
    return str;
}

