            exp = str.substring(expPos + 1);
        } else {
            exp = null;
        }
        //Requesting a specific type..
        String numeric = str.substring(0, str.length() - 1);
        boolean allZeros = isAllZeros(mant) && isAllZeros(exp);
        switch (lastChar) {
            case 'l' :
            case 'L' :
                if (dec == null
                    && exp == null
                    && isDigits(numeric.replaceAll("^-", ""))
                    && (numeric.charAt(0) == '-' || Character.isDigit(numeric.charAt(0)))) {
                    try {
                        return createLong(numeric);
                    } catch (NumberFormatException nfe) {
                        //Too big for a long
                    }
                    return createBigInteger(numeric);

                }
                throw new NumberFormatException(str + " is not a valid number.");
            case 'f' :
            case 'F' :
                try {
                    Float f = NumberUtils.createFloat(numeric);
                    if (!(f.isInfinite() || (f.floatValue() == 0.0F && !allZeros))) {
                        //If it's too big for a float or the float value = 0 and the string
                        //has non-zeros in it, then float does not have the precision we want
                        return f;
                    }

                } catch (NumberFormatException nfe) {
                    // ignore the bad number
                }
                //Fall through
            case 'd' :
            case 'D' :
                try {
                    Double d = NumberUtils.createDouble(numeric);
                    if (!(d.isInfinite() || (d.doubleValue() == 0.0D && !allZeros))) {
                        return d;
                    }
                } catch (NumberFormatException nfe) {
                    // ignore the bad number
                }
                try {
                    return createBigDecimal(numeric);
                } catch (NumberFormatException e) {
                    // ignore the bad number
                }
                //Fall through
            default :
                throw new NumberFormatException(str + " is not a valid number.");

        }
    } else {
        //User doesn't have a preference on the return type, so let's start
        //small and go from there...
        if (expPos > -1 && expPos < str.length() - 1) {
            exp = str.substring(expPos + 1);
        } else {
            exp = null;
        }
        if (dec == null && exp == null) {
            //Must be an int,long,bigint
            try {
                return createInteger(str);
            } catch (NumberFormatException nfe) {
                // ignore the bad number
            }
            try {
                return createLong(str);
            } catch (NumberFormatException nfe) {
                // ignore the bad number
            }
            return createBigInteger(str);

        } else {
            //Must be a float,double,BigDec
            boolean allZeros = isAllZeros(mant) && isAllZeros(exp);
            try {
                Float f = createFloat(str);
                if (!(f.isInfinite() || (f.floatValue() == 0.0F && !allZeros))) {
                    return f;
                }
            } catch (NumberFormatException nfe) {
                // ignore the bad number
            }
            try {
                Double d = createDouble(str);
                if (!(d.isInfinite() || (d.doubleValue() == 0.0D && !allZeros))) {
                    return d;
                }
            } catch (NumberFormatException nfe) {
                // ignore the bad number
            }

            return createBigDecimal(str);

        }
    }
}

public static Number createNumber(String str) throws NumberFormatException {
    if (str == null) {
        return null;
    }
    if (StringUtils.isBlank(str)) {
        throw new NumberFormatException("A blank string is not a valid number");
    }  
    if (str.startsWith("--")) {
        // this is protection for poorness in java.lang.BigDecimal.
        // it accepts this as a legal value, but it does not appear 
        // to be in specification of class. OS X Java parses it to 
        // a wrong value.
        return null;
    }
    if (str.startsWith("0x") || str.startsWith("-0x")) {
        return createInteger(str);
    }   
    char lastChar = str.charAt(str.length() - 1);
    String numericPart = str;
    boolean isTypeSpecified = false;

    if (!Character.isDigit(lastChar)) {
        switch (lastChar) {
            case 'l':
            case 'L':
            case 'f':
            case 'F':
            case 'd':
            case 'D':
                numericPart = str.substring(0, str.length() - 1);
                isTypeSpecified = true;
                break;
            default:
                throw new NumberFormatException(str + " is not a valid number.");
        }
    }

    try {
        if (isTypeSpecified) {
            switch (lastChar) {
                case 'l':
                case 'L':
                    return createLong(numericPart);
                case 'f':
                case 'F':
                    return createFloat(numericPart);
                case 'd':
                case 'D':
                    return createDouble(numericPart);
            }
        } else {
            // Try parsing as Integer first
            return createInteger(numericPart);
        }
    } catch (NumberFormatException nfe) {
        // Ignore and continue to next type
    }

    try {
        if (isTypeSpecified) {
            if (lastChar == 'l' || lastChar == 'L') {
                return createBigInteger(numericPart);
            }
        } else {
            // Try parsing as Long
            return createLong(numericPart);
        }
    } catch (NumberFormatException nfe) {
        // Ignore and continue to next type
    }

    try {
        if (isTypeSpecified) {
            if (lastChar == 'f' || lastChar == 'F') {
                Float f = NumberUtils.createFloat(numericPart);
                if (!(f.isInfinite() || (f.floatValue() == 0.0F && !isAllZeros(numericPart)))) {
                    return f;
                }
            } else if (lastChar == 'd' || lastChar == 'D') {
                Double d = NumberUtils.createDouble(numericPart);
                if (!(d.isInfinite() || (d.doubleValue() == 0.0D && !isAllZeros(numericPart)))) {
                    return d;
                }
            }
        } else {
            // Try parsing as Float
            Float f = createFloat(numericPart);
            if (!(f.isInfinite() || (f.floatValue() == 0.0F && !isAllZeros(numericPart)))) {
                return f;
            }
        }
    } catch (NumberFormatException nfe) {
        // Ignore and continue to next type
    }

    try {
        if (isTypeSpecified) {
            if (lastChar == 'd' || lastChar == 'D') {
                return createBigDecimal(numericPart);
            }
        } else {
            // Try parsing as Double
            Double d = createDouble(numericPart);
            if (!(d.isInfinite() || (d.doubleValue() == 0.0D && !isAllZeros(numericPart)))) {
                return d;
            }
        }
    } catch (NumberFormatException nfe) {
        // Ignore and continue to next type
    }

    // Finally, try parsing as BigDecimal
    return createBigDecimal(numericPart);
}

public StrBuilder appendFixedWidthPadRight(Object obj, int width, char padChar) {
    if (width > 0) {
        ensureCapacity(size + width);
        String str = (obj == null ? getNullText() : obj.toString());
        int strLen = str.length();
        if (strLen >= width) {
            str.getChars(0, width, buffer, size);
        } else {
            int padLen = width - strLen;
            str.getChars(0, strLen, buffer, size);
            for (int i = 0; i < padLen; i++) {
                buffer[size + strLen + i] = padChar;
            }
        }
        size += Math.min(width, strLen);
    }
    return this;
}

