private double[] getUpperBounds(int length) {
    // Implement this method to provide the actual upper bounds dynamically
    double[] bounds = new double[length];
    Arrays.fill(bounds, 0.5);
    return bounds;
}

private double[] clipToBounds(double[] values, double[] lowerBounds, double[] upperBounds) {
    double[] clippedValues = new double[values.length];
    for (int i = 0; i < values.length; i++) {
        if (!Double.isFinite(values[i])) {
            throw new IllegalArgumentException("Input array contains non-finite values");
        }
        clippedValues[i] = Math.max(lowerBounds[i], Math.min(values[i], upperBounds[i]));
    }
    return clippedValues;
}

protected UnivariatePointValuePair doOptimize() {
    final boolean isMinim = getGoalType() == GoalType.MINIMIZE;
    final double lo = getMin();
    final double mid = getStartValue();
    final double hi = getMax();

    // Optional additional convergence criteria.
    final ConvergenceChecker<UnivariatePointValuePair> checker
        = getConvergenceChecker();

    double a;
    double b;
    if (lo < hi) {
        a = lo;
        b = hi;
    } else {
        a = hi;
        b = lo;
    }

    double x = mid;
    double v = x;
    double w = x;
    double d = 0;
    double e = 0;
    double fx = computeObjectiveValue(x);
    if (!isMinim) {
        fx = -fx;
    }
    double fv = fx;
    double fw = fx;

    UnivariatePointValuePair previous = null;
    UnivariatePointValuePair current = new UnivariatePointValuePair(x, isMinim ? fx : -fx);
    UnivariatePointValuePair best = current; // Initialize best with the first computed point

    int iter = 0;
    while (true) {
        final double m = 0.5 * (a + b);
        final double tol1 = relativeThreshold * FastMath.abs(x) + absoluteThreshold;
        final double tol2 = 2 * tol1;

        // Default stopping criterion.
        final boolean stop = FastMath.abs(x - m) <= tol2 - 0.5 * (b - a);
        if (!stop) {
            double p = 0;
            double q = 0;
            double r = 0;
            double u = 0;

