u1 = u1.normalize();
u2 = u2.normalize();
v1 = v1.normalize();
v2 = v2.normalize();

// adjust v2 in order to have (u1|u2) = (v1'|v2') and (v2'|v2') = (u2|u2)
double u1u2 = u1.dotProduct(u2);
double v1v2 = v1.dotProduct(v2);
double coeffU = u1u2;
double coeffV = v1v2;
double betaSquared = (1 - u1u2 * u1u2) / (1 - v1v2 * v1v2);
