public double cumulativeProbability(double x) throws MathException {
    final double dev = x - mean;
    final double threshold = 40 * standardDeviation;

    if (Double.isInfinite(dev) || Math.abs(dev) > threshold) {
        return dev < 0 ? 0 : 1;
    }

    try {
        return 0.5 * (1.0 + Erf.erf(dev / (standardDeviation * FastMath.sqrt(2.0))));
    } catch (MaxIterationsExceededException ex) {
        if (x < (mean - 20 * standardDeviation)) {
            return 0;
        } else if (x > (mean + 20 * standardDeviation)) {
            return 1;
        } else {
            throw ex;
        }
    }
}

public double cumulativeProbability(double x) throws MathException {
    final double dev = x - mean;
    final double threshold = standardDeviation * FastMath.sqrt(-2.0 * FastMath.log(Double.MIN_NORMAL));
    try {
        if (dev < -threshold) {
            return 0;
        } else if (dev > threshold) {
            return 1;
        } else {
            return 0.5 * (1.0 + Erf.erf(dev / (standardDeviation * FastMath.sqrt(2.0))));
        }
    } catch (MaxIterationsExceededException ex) {
        if (dev < -threshold) {
            return 0;
        } else if (dev > threshold) {
            return 1;
        } else {
            throw ex;
        }
    }
}

public RealMatrix getCorrelationPValues() throws MathException {
    TDistribution tDistribution = new TDistributionImpl(nObs - 2);
    int nVars = correlationMatrix.getColumnDimension();
    double[][] out = new double[nVars][nVars];
    for (int i = 0; i < nVars; i++) {
        for (int j = 0; j < nVars; j++) {
            if (i == j) {
                out[i][j] = 0d;
            } else {
                double r = correlationMatrix.getEntry(i, j);
                if (Math.abs(r) >= 1) {
                    out[i][j] = 0d; // If r is exactly -1 or 1, p-value is 0
                } else {
                    double t = Math.abs(r) * Math.sqrt((nObs - 2) / (1 - r * r));
                    double pValue = 2 * (1 - tDistribution.cumulativeProbability(t));
                    if (Double.isNaN(pValue) || pValue <= 0) {
                        pValue = Double.MIN_NORMAL; // Use the smallest positive normal value
                    }
                    out[i][j] = pValue;
                }
            }
        }
    }
    return new BlockRealMatrix(out);
}

