                double imagTolerance = Math.max(Math.ulp(imaginary), Math.ulp(rhs.getImaginary()));
                ret = Math.abs(real - rhs.getReal()) <= realTolerance && Math.abs(imaginary - rhs.getImaginary()) <= imagTolerance;
