        Object mock = invocation.getMock();
        if (argument == null) {
            return 1;
        }
        if (argument == mock || (argument instanceof Comparable && argument.equals(mock))) {
            return 0;
        } else {
            return 1;
        }
    }

    Class<?> returnType = invocation.getMethod().getReturnType();
    return returnValueFor(returnType);
}

private void injectMockCandidate(Class<?> awaitingInjectionClazz, Set<Object> mocks, Object fieldInstance) {
    for(Field field : orderedInstanceFieldsFrom(awaitingInjectionClazz)) {
        Object mockToInject = mockCandidateFilter.filterCandidate(mocks, field, fieldInstance);
        if (mockToInject != null) {
            try {
                field.setAccessible(true);
                field.set(fieldInstance, mockToInject);
            } catch (IllegalAccessException e) {
                System.err.println("Could not inject mock into field " + field.getName() + ": " + e.getMessage());
            }
        }
    }
}

