private void createSynthesizedExternVar(String varName) {
    if (varName == null || varName.isEmpty()) {
        throw new IllegalArgumentException("Variable name cannot be null or empty");
    }

    Node nameNode = Node.newString(Token.NAME, varName);

    // Mark the variable as constant if it matches the coding convention
    // for constant vars.
    if (compiler != null && compiler.getCodingConvention() != null && compiler.getCodingConvention().isConstant(varName)) {
        nameNode.putBooleanProp(Node.IS_CONSTANT_NAME, true);
    }

    Node synthesizedExternsRoot = getSynthesizedExternsRoot();
    if (synthesizedExternsRoot != null) {
        synthesizedExternsRoot.addChildToBack(new Node(Token.VAR, nameNode));
    } else {
        throw new IllegalStateException("Synthesized externs root node is not initialized");
    }

    if (varsToDeclareInExterns != null) {
        varsToDeclareInExterns.remove(varName);
    }

    if (compiler != null) {
        compiler.reportCodeChange();
    }
}

